export function readLines(text, callback) {
  try {
    if (typeof text !== 'string') {
      callback(new TypeError('Input must be a string'));
      return;
    }
    const lines = text.split('\n');
    callback(null, lines);
  } catch (err) {
    callback(err);
  }
}

