import { readLines } from '../src/readLines.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

async function runTests() {
  // Test 1: normal text splits into lines
  const r1 = await readLines('hello\nworld\nfoo');
  assert(JSON.stringify(r1) === JSON.stringify(['hello', 'world', 'foo']), 'readLines should split by newline but got ' + JSON.stringify(r1));

  // Test 2: empty string returns array with one empty string
  const r2 = await readLines('');
  assert(JSON.stringify(r2) === JSON.stringify(['']), 'readLines("") should return [""] but got ' + JSON.stringify(r2));

  // Test 3: single line with no newlines
  const r3 = await readLines('single line');
  assert(JSON.stringify(r3) === JSON.stringify(['single line']), 'readLines("single line") should return ["single line"] but got ' + JSON.stringify(r3));

  // Test 4: returns a promise
  const result = readLines('test');
  assert(result instanceof Promise, 'readLines should return a Promise');

  // Test 5: rejects on non-string input
  try {
    await readLines(123);
    assert(false, 'Should have thrown for non-string input');
  } catch (e) {
    assert(e instanceof TypeError, 'Should throw TypeError for non-string input');
  }

  console.log('ALL TESTS PASSED');
}

runTests();
